		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Martinet&lt;/span&gt;&amp;nbsp;is&amp;nbsp;a person who demands complete obedience; a strict disciplinarian.&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;Defeatist&lt;/strong&gt;&amp;nbsp;is&amp;nbsp;a person who expects or is excessively ready to accept failure.&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;Sycophant&lt;/strong&gt;&amp;nbsp;is&amp;nbsp;a person who acts obsequiously towards someone important in order to gain an advantage.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Hence&lt;/span&gt;, a schoolboy who cuts classes frequently is a &amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;Truant&lt;/span&gt;&amp;#39;.&lt;br /&gt;
	&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;The&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;synonyms&amp;nbsp;&lt;/span&gt;of the word&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&amp;#39;Truant&amp;#39;&lt;/span&gt;&amp;nbsp;are&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&amp;quot;&lt;/span&gt;&lt;strong&gt;absent, away, missing&lt;/strong&gt;&amp;quot;.&lt;/li&gt;
	&lt;li&gt;The&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;antonyms&amp;nbsp;&lt;/span&gt;of the word&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&amp;#39;Truant&amp;#39;&lt;/span&gt;&amp;nbsp;are&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&amp;quot;&lt;/span&gt;&lt;strong&gt;accompanying, attending, participating&lt;/strong&gt;&amp;quot;.&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Example&lt;/span&gt;&amp;nbsp;of &amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;Truant&lt;/span&gt;&amp;#39; in a&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;sentence&lt;/span&gt;&lt;/u&gt;:
